127	          title: "Google sign-in failed",
128	          description: error.message,
129	          variant: "destructive"
130	        });
131	        setIsGoogleLoading(false);
132	      }
133	    } catch (err) {
134	      console.error("Google auth error:", err);
135	      toast({
136	        title: "Connection error",
137	        description: "Unable to connect to Google. Please check your internet and try again.",
138	        variant: "destructive"
139	      });
140	      setIsGoogleLoading(false);
141	    }
142	  };
