187	        }
188	        const { data: signUpData, error } = await supabase.auth.signUp({
189	          email: email.trim(),
190	          password,
191	          options: {
192	            emailRedirectTo: `${window.location.origin}/auth`,
193	            data: {
194	              user_type: 'creator',
195	            },
196	          },
197	        });
198	
199	        if (error) {
200	          const msg = error.message.toLowerCase();
201	          if (msg.includes("already registered") || msg.includes("already exists")) {
202	            toast({
203	              title: "Account already exists",
204	              description: "An account with this email already exists. Try logging in instead.",
205	              variant: "destructive",
206	            });
207	            setIsSignup(false);
208	          } else if (msg.includes("rate limit") || msg.includes("email rate")) {
209	            toast({
210	              title: "Too many attempts",
211	              description: "Please wait a few minutes before trying again.",
212	              variant: "destructive",
213	            });
214	          } else {
215	            toast({
