217	              description: "Something went wrong on our end. Please try again in a moment.",
218	              variant: "destructive",
219	            });
220	            console.error("Signup error:", error.message);
221	          }
222	        } else if (signUpData.session) {
223	          // User is immediately signed in (email confirmation disabled)
224	          const { data: aalData } = await supabase.auth.mfa.getAuthenticatorAssuranceLevel();
225	          if (aalData?.nextLevel === "aal2" && aalData?.nextLevel !== aalData?.currentLevel) {
226	            navigate("/mfa-verify", { replace: true });
227	          } else {
228	            navigate("/kira", { replace: true });
