233	          setEmailConfirmPending(true);
234	        }
235	      } else {
236	        const { data, error } = await supabase.auth.signInWithPassword({
237	          email: email.trim(),
238	          password,
239	        });
240	
241	        if (error) {
242	          const msg = error.message.toLowerCase();
243	          if (msg.includes("invalid login") || msg.includes("invalid credentials") || msg.includes("wrong password")) {
244	            toast({ title: "Incorrect email or password", description: "Please check your details and try again. If you signed up with Google, use the Google button above.", variant: "destructive" });
245	          } else if (msg.includes("email not confirmed")) {
246	            toast({ title: "Email not confirmed", description: "Please check your inbox and click the confirmation link we sent you.", variant: "destructive" });
247	          } else {
248	            toast({ title: "Sign in failed", description: error.message, variant: "destructive" });
249	          }
250	        } else if (data.user) {
251	          toast({ title: "Welcome back!", description: "Good to see you." });
252	          // navigation is handled by the onAuthStateChange SIGNED_IN listener above
253	        }
254	      }
255	    } catch (err) {
256	      console.error("Auth error:", err);
257	      toast({ 
258	        title: "Connection hiccup! 📡", 
259	        description: "Unable to connect to the server. Please check your internet and try again.", 
260	        variant: "destructive" 
261	      });
262	    } finally {
263	      setIsLoading(false);
264	    }
265	  };
