311	            <p className="text-muted-foreground text-sm leading-relaxed">
312	              An email was sent to<br />
313	              <span className="font-semibold text-foreground">{pendingEmail}</span>
314	            </p>
315	          </div>
316	          <p className="text-sm text-muted-foreground mb-6">
317	            Kindly click the link in the email to confirm your account and get access to Kira. Check your spam folder if you don't see it.
318	          </p>
319	          <Button
320	            className="w-full h-12 bg-bronze hover:bg-bronze-dark font-semibold"
321	            onClick={handleResendConfirmation}
322	            disabled={isResendingConfirm}
323	          >
324	            {isResendingConfirm ? "Sending..." : "Resend confirmation link"}
325	          </Button>
