336	            <img 
337	              src="/crevia-logo.png" 
338	              alt="Crevia Logo" 
339	              className="w-8 h-8 md:w-10 md:h-10 transition-transform duration-[400ms] ease-[cubic-bezier(0.32,0.72,0,1)] hover:scale-105" 
340	            />
341	            <span className="font-vollkorn text-2xl md:text-3xl font-bold">Crevia</span>
342	          </Link>
343	          <h1 className="font-vollkorn text-2xl md:text-3xl font-bold mb-2 animate-fade-in stagger-1 animate-stagger">
344	            {isSignup ? "Create your account" : "Welcome back"}
345	          </h1>
346	          <p className="text-sm md:text-base text-muted-foreground animate-fade-in stagger-2 animate-stagger">
347	            {isSignup ? "Sign up to get started" : "Log in to continue"}
348	          </p>
349	        </div>
350	
351	
352	        <div className="justify-center">
353	          <Button 
354	            variant="outline" 
