2	import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
3	
4	const ALLOWED_ORIGINS = [
5	  'https://crevia.app',
6	  'https://www.crevia.app',
7	  'http://localhost:8080',
8	  'http://localhost:5173',
9	  'https://creviamvp.vercel.app',
10	];
11	
12	function getCorsHeaders(req: Request) {
13	  const origin = req.headers.get('Origin') ?? '';
14	  const allowed = ALLOWED_ORIGINS.includes(origin) ? origin : ALLOWED_ORIGINS[0];
15	  return {
16	    'Access-Control-Allow-Origin': allowed,
17	    'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
18	    'Vary': 'Origin',
19	  };
20	}
21	
22	const VALID_CURRENCIES = ['KES', 'USD', 'EUR', 'GBP', 'NGN', 'ZAR', 'GHS', 'TZS', 'UGX'];
23	
24	interface InvoiceItem {
25	  description: string;
26	  quantity: number;
27	  unit_price: number;
28	  total: number;
29	}
30	
31	serve(async (req) => {
32	  const cors = getCorsHeaders(req);
33	
34	  if (req.method === 'OPTIONS') {
35	    return new Response(null, { headers: cors });
36	  }
37	
38	  if (req.method !== 'POST') {
39	    return new Response(JSON.stringify({ error: 'Method not allowed' }), {
40	      status: 405,
41	      headers: { ...cors, 'Content-Type': 'application/json' },
42	    });
43	  }
44	
45	  try {
46	    // === AUTH VALIDATION ===
47	    const authHeader = req.headers.get('Authorization');
48	    if (!authHeader?.startsWith('Bearer ')) {
49	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
50	        status: 401,
51	        headers: { ...cors, 'Content-Type': 'application/json' },
52	      });
53	    }
54	
55	    const supabase = createClient(
56	      Deno.env.get('SUPABASE_URL')!,
57	      Deno.env.get('SUPABASE_ANON_KEY')!,
58	      { global: { headers: { Authorization: authHeader } } }
59	    );
60	
61	    const token = authHeader.replace('Bearer ', '');
62	    const { data: claimsData, error: claimsError } = await supabase.auth.getClaims(token);
63	    if (claimsError || !claimsData?.claims) {
64	      return new Response(JSON.stringify({ error: 'Unauthorized' }), {
65	        status: 401,
66	        headers: { ...cors, 'Content-Type': 'application/json' },
67	      });
68	    }
69	
70	    const userId = claimsData.claims.sub;
71	    // === END AUTH VALIDATION ===
72	
73	    // === INPUT VALIDATION ===
74	    let body: Record<string, unknown>;
75	    try {
76	      body = await req.json();
77	    } catch {
78	      return new Response(JSON.stringify({ error: 'Invalid JSON body' }), {
79	        status: 400,
80	        headers: { ...cors, 'Content-Type': 'application/json' },
81	      });
82	    }
83	
84	    const { invoice_number, client_name, client_email, client_address, issue_date,
85	            due_date, tax_rate, discount_amount, notes, terms, currency, items } = body as Record<string, unknown>;
86	
87	    if (!client_name || typeof client_name !== 'string' || client_name.trim().length === 0) {
88	      return new Response(JSON.stringify({ error: 'client_name is required' }), {
89	        status: 400,
90	        headers: { ...cors, 'Content-Type': 'application/json' },
91	      });
92	    }
93	
94	    if (!due_date || typeof due_date !== 'string') {
95	      return new Response(JSON.stringify({ error: 'due_date is required' }), {
96	        status: 400,
97	        headers: { ...cors, 'Content-Type': 'application/json' },
98	      });
99	    }
100	
101	    if (!Array.isArray(items) || items.length === 0) {
102	      return new Response(JSON.stringify({ error: 'At least one invoice item is required' }), {
103	        status: 400,
104	        headers: { ...cors, 'Content-Type': 'application/json' },
105	      });
106	    }
107	
108	    // Validate each item
109	    for (const item of items as InvoiceItem[]) {
110	      if (!item.description || typeof item.description !== 'string') {
111	        return new Response(JSON.stringify({ error: 'Each item must have a description' }), {
112	          status: 400,
113	          headers: { ...cors, 'Content-Type': 'application/json' },
114	        });
115	      }
116	      if (typeof item.quantity !== 'number' || item.quantity <= 0) {
117	        return new Response(JSON.stringify({ error: 'Each item must have a positive quantity' }), {
118	          status: 400,
119	          headers: { ...cors, 'Content-Type': 'application/json' },
120	        });
121	      }
122	      if (typeof item.unit_price !== 'number' || item.unit_price < 0) {
123	        return new Response(JSON.stringify({ error: 'Each item must have a valid unit_price' }), {
124	          status: 400,
125	          headers: { ...cors, 'Content-Type': 'application/json' },
126	        });
127	      }
128	    }
129	
130	    // Generate invoice number if not provided
131	    const resolvedInvoiceNumber = (typeof invoice_number === 'string' && invoice_number.trim())
132	      ? invoice_number.trim()
