137	
138	    const resolvedTaxRate = typeof tax_rate === 'number' && tax_rate >= 0 ? tax_rate : 0;
139	    const resolvedDiscount = typeof discount_amount === 'number' && discount_amount >= 0 ? discount_amount : 0;
140	
141	    // Calculate totals
142	    const subtotal = (items as InvoiceItem[]).reduce((sum, item) => sum + (item.quantity * item.unit_price), 0);
143	    const taxAmount = subtotal * (resolvedTaxRate / 100);
144	    const total = subtotal + taxAmount - resolvedDiscount;
145	    // === END INPUT VALIDATION ===
146	
147	    // Insert invoice
148	    const { data: invoice, error: invoiceError } = await supabase
149	      .from('invoices')
150	      .insert({
151	        user_id: userId,
152	        invoice_number: resolvedInvoiceNumber,
153	        client_name: (client_name as string).trim(),
154	        client_email: typeof client_email === 'string' ? client_email.trim() : null,
155	        client_address: typeof client_address === 'string' ? client_address.trim() : null,
156	        issue_date: typeof issue_date === 'string' ? issue_date : new Date().toISOString().split('T')[0],
157	        due_date: due_date as string,
158	        status: 'draft',
159	        subtotal,
160	        tax_rate: resolvedTaxRate,
161	        tax_amount: taxAmount,
162	        discount_amount: resolvedDiscount,
163	        total,
164	        notes: typeof notes === 'string' ? notes : null,
165	        terms: typeof terms === 'string' ? terms : null,
166	        currency: resolvedCurrency,
167	      })
