169	      .single();
170	
171	    if (invoiceError) {
172	      console.error('invoices-create insert error:', invoiceError);
173	      return new Response(JSON.stringify({ error: 'Failed to create invoice' }), {
174	        status: 500,
175	        headers: { ...cors, 'Content-Type': 'application/json' },
176	      });
177	    }
178	
179	    // Insert invoice items
180	    const invoiceItems = (items as InvoiceItem[]).map((item) => ({
181	      invoice_id: invoice.id,
182	      description: item.description,
183	      quantity: item.quantity,
184	      unit_price: item.unit_price,
185	      total: item.quantity * item.unit_price,
186	    }));
187	
188	    const { error: itemsError } = await supabase.from('invoice_items').insert(invoiceItems);
189	
190	    if (itemsError) {
191	      console.error('invoices-create items insert error:', itemsError);
